  ('judicial-57f41407-moex-00194', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於刑法不罰之規定，何者錯誤？', '["未滿14歲人之行為", "行為非出於故意或重大過失者", "依法令之行為", "業務上之正當行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
