  ('judicial-57f41407-moex-00196', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '匯率的變動會影響一國的進出口變化，也會對個人產生實質影響。在外匯市場上，當新臺幣對美元不斷升 值時，對下列那些人較為不利？', '["到美國去自助旅行的臺灣觀光客", "準備投資美元外匯的臺灣投資人", "出口手機到美國的臺灣科技廠商", "進口美國巧克力的臺灣貿易公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00197', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '假設應提準備率為20%，且社會大眾其所持有的通貨之於其存款的比率為1：3。若通貨發行額為100元， 則總存款的最大可能金額介於下列何者之間？', '["（150元，175元）", "（175元，200元）", "（200元，225元）", "（225元，250元）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00198', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '快樂幸福的反面是痛苦，而經濟學所謂「痛苦指數」是由失業率加下列那一指標之總和？', '["利率", "消費者物價上漲率", "匯率", "稅率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00199', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列何種情況可以代表同一需求線上點的移動？', '["夏季碳酸飲料漲價，使得手搖茶飲業績翻倍", "不少民眾預期奶粉將漲價，紛紛到賣場囤貨", "石油價格大漲，讓有意買車代步的民眾縮手", "中秋節的文旦價格翻漲，民眾只好少吃一點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00200', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '資源技術相同的甲國與乙國都生產香米跟芒果，假設兩國各自的生產可能線（芒果為橫軸，香米為縱軸） 均是直線，且甲國生產可能線較乙國陡。假設貿易前甲國生產的芒果比乙國多，乙國生產的香米比甲國多。 下列針對兩國生產兩種產品的專業分工之敘述，何者正確？', '["甲國具有生產芒果的比較利益", "乙國具有生產香米的絕對利益", "甲國具有生產香米的比較利益", "乙國沒有生產芒果的絕對利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00201', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '美國著名社會心理學家米德（G.H.Mead）的論點，主要以「主我」跟「客我」來說明個人自我發展的歷程。 有關其理論敘述，下列何者正確？', '["「主我」的支配讓個人行為趨向符合社會期望", "「主我」的支配讓個人較不易受社會規範約束", "「客我」的作用類似佛洛伊德理論中的「本我」", "「客我」主要是讓原始衝動追求個人慾望滿足"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00202', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '高雄燕巢區的金山里，由里長帶領熱心居民組成的志工隊，將里內閒置空地綠化，同時透過種植多樣性樹 種復育環境，還規劃低碳旅遊多項行程路線，結合環保小學堂、農村DIY體驗等活動，提供一般民眾報名 體驗。下列敘述何者最能說明上述現象？', '["社會價值的變遷對永續發展的正面影響", "社區組織的成立致使經費分配具公平性", "社區意識的凝聚與社區營造成功的關連", "民間志願團體對政府財政工作的協助與推展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
